"""
Mock FastAPI Routes
"""
from fastapi import FastAPI, Depends, HTTPException
from pydantic import BaseModel
from backend.auth import AuthService
from backend.payment import PaymentService
from backend.database import UserRepository, PaymentRepository

app = FastAPI()
user_repo = UserRepository()
payment_repo = PaymentRepository()
auth_service = AuthService(user_repo)
payment_service = PaymentService(auth_service, payment_repo)


class LoginRequest(BaseModel):
    username: str
    password: str


class PaymentRequest(BaseModel):
    token: str
    amount: int
    currency: str = "usd"


@app.post("/api/login")
def login(req: LoginRequest):
    try:
        return auth_service.login(req.username, req.password)
    except ValueError as e:
        raise HTTPException(status_code=401, detail=str(e))


@app.post("/api/payment")
def payment(req: PaymentRequest):
    try:
        return payment_service.process_payment(req.token, req.amount, req.currency)
    except PermissionError as e:
        raise HTTPException(status_code=403, detail=str(e))


@app.get("/api/health")
def health():
    return {"status": "ok"}

import React, { useState } from 'react';
import axios from 'axios';

const Checkout = () => {
  const [status, setStatus] = useState('');

  const handlePayment = async () => {
    const token = localStorage.getItem('token');
    try {
      const res = await axios.post('/api/payment', {
        token,
        amount: 4999,
        currency: 'usd',
      });
      setStatus(`Payment successful! Charge ID: ${res.data.charge_id}`);
    } catch (err) {
      setStatus('Payment failed: ' + (err.response?.data?.detail || 'Unknown error'));
    }
  };

  return (
    <div className="checkout-page">
      <h2>Checkout</h2>
      <button onClick={handlePayment}>Pay $49.99</button>
      {status && <p>{status}</p>}
    </div>
  );
};

export default Checkout;

import React, { useState } from 'react';
import axios from 'axios';

const Login = () => {
  const [form, setForm] = useState({ username: '', password: '' });
  const [error, setError] = useState('');

  const handleLogin = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post('/api/login', form);
      localStorage.setItem('token', res.data.access_token);
      window.location.href = '/dashboard';
    } catch (err) {
      setError(err.response?.data?.detail || 'Login failed');
    }
  };

  return (
    <div className="login-page">
      <form onSubmit={handleLogin}>
        <input
          type="text"
          placeholder="Username"
          value={form.username}
          onChange={(e) => setForm({ ...form, username: e.target.value })}
        />
        <input
          type="password"
          placeholder="Password"
          value={form.password}
          onChange={(e) => setForm({ ...form, password: e.target.value })}
        />
        {error && <p className="error">{error}</p>}
        <button type="submit">Login</button>
      </form>
    </div>
  );
};

export default Login;
